import { Component, inject, signal, computed, DestroyRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import {
  Subject,
  debounceTime,
  startWith,
  catchError,
  of,
  tap,
  switchMap,
} from 'rxjs';

import { AppStoreService } from '../../services/app-store.service';
import { AppInstallFacadeService } from '../../services/app-install-facade.service';
import { AppDefinitionListItem } from '../../models/app-store.models';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { ClientDataService } from '../../../clients/services/client-data.service';

import { AppCardComponent } from '../../components/app-card/app-card.component';
import { AppFilterBarComponent } from '../../components/app-filter-bar/app-filter-bar.component';
import {
  MARKETPLACE_CATEGORIES,
  MARKETPLACE_SORT_OPTIONS,
} from '../../configs/marketplace.config';
import { isNullOrUndefined } from '../../../../shared/utils';

@Component({
  selector: 'app-marketplace',
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    AppCardComponent,
    AppFilterBarComponent,
  ],
  templateUrl: './app-marketplace.component.html',
  styleUrls: ['./app-marketplace.component.scss'],
})
export class AppMarketplaceComponent {
  private readonly appStoreService = inject(AppStoreService);
  private readonly installFacade = inject(AppInstallFacadeService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly authDataService = inject(AuthDataService);
  private readonly clientDataService = inject(ClientDataService);

  // State Signals
  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);
  readonly categoryFilter = signal('All');
  readonly sortOrder = signal('popular');
  readonly actionAppId = signal<string | null>(null);

  // Static Data from Config
  readonly categories = MARKETPLACE_CATEGORIES;
  readonly sortOptions = MARKETPLACE_SORT_OPTIONS;

  private readonly searchInput$ = new Subject<string>();
  private readonly searchQuery$ = this.searchInput$.pipe(
    debounceTime(250),
    startWith(''),
  );
  readonly searchQuery = toSignal(this.searchQuery$, { initialValue: '' });

  private readonly refreshTrigger = signal(0);

  // Fetch marketplace apps — installation context comes back in app.installation
  private readonly rawApps = toSignal(
    toObservable(this.refreshTrigger).pipe(
      tap(() => this.isLoading.set(true)),
      switchMap(() => {
        const clientId = this.clientDataService.getSelectedClient()?.id ?? '';
        return this.appStoreService.getApps({ owner: clientId }).pipe(
          tap(() => this.isLoading.set(false)),
          catchError((err) => {
            console.error('Error loading apps:', err);
            this.error.set('Unable to load apps. Please try again.');
            this.isLoading.set(false);
            return of([] as AppDefinitionListItem[]);
          }),
        );
      }),
    ),
    { initialValue: [] as AppDefinitionListItem[] },
  );

  // Computed Signal for Filtered & Sorted Apps
  readonly apps = computed(() => {
    const apps = this.rawApps();
    const query = (this.searchQuery() || '').toLowerCase();
    const category = this.categoryFilter();
    const sort = this.sortOrder();

    const filtered = apps.filter((app) => {
      const matchesSearch =
        app.name.toLowerCase().includes(query) ||
        app.shortDescription.toLowerCase().includes(query);
      const matchesCategory =
        category === 'All' || app.categories.includes(category);
      return matchesSearch && matchesCategory;
    });

    return filtered.sort((a, b) => {
      if (sort === 'popular')
        return b.stats.installCount - a.stats.installCount;
      if (sort === 'newest')
        return (
          new Date(b.createdDate).getTime() - new Date(a.createdDate).getTime()
        );
      if (sort === 'rating')
        return b.stats.averageRating - a.stats.averageRating;
      return 0;
    });
  });

  readonly isAdmin = this.authDataService.isSuperAdmin();

  onSearch(query: string): void {
    this.searchInput$.next(query);
  }

  onCategorySelect(category: string): void {
    this.categoryFilter.set(category);
  }

  onSortChange(sort: string): void {
    this.sortOrder.set(sort);
  }

  installApp(app: AppDefinitionListItem): void {
    this.actionAppId.set(app.id);
    this.installFacade.installApp(app, this.destroyRef, () => {
      this.actionAppId.set(null);
      this.refreshTrigger.update((n) => n + 1);
    });
  }

  uninstallApp(app: AppDefinitionListItem): void {
    if (isNullOrUndefined(app.installation?.id)) return;
    const isExternalApp =
      app.integrationPoints?.some((p) => p.screenId === 'appSidebar') ?? false;

    this.actionAppId.set(app.id);
    this.installFacade.uninstallApp(app.installation?.id, isExternalApp, () => {
      this.actionAppId.set(null);
      this.refreshTrigger.update((n) => n + 1);
    });
  }
}
